-- Enrichment marathon batch: Converse.js, Convex, Convoy, Coolify, Copper, Copy.ai, Coral (The Coral Project), Coralogix

-- ── Converse.js ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Free, open-source XMPP/Jabber chat client written in JavaScript that runs entirely in the browser, embeddable as a widget or deployed as a full-page messaging app.$q$, short_description),
  pricing_model = COALESCE($q$Free/Open Source$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2012, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE(NULL, headquarters),
  languages = ARRAY[$q$English$q$, $q$German$q$, $q$French$q$, $q$Spanish$q$, $q$Russian$q$, $q$Chinese$q$, $q$Portuguese$q$, $q$and 40+ other translated locales$q$]::text[],
  seo_title = COALESCE($q$Converse.js: Open-Source XMPP Web Chat Client$q$, seo_title),
  seo_meta_description = COALESCE($q$Converse.js is a free, open-source XMPP/Jabber chat client for the browser. Embed real-time messaging with OMEMO encryption and group chats on any site.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Converse.js is a free and open-source, browser-based chat client for the XMPP (Extensible Messaging and Presence Protocol, also known as Jabber) instant-messaging protocol. Written entirely in JavaScript, it runs client-side and connects to any standards-compliant XMPP server, letting developers add real-time one-on-one chat, multi-user group chats (MUC), and presence features to a website without building a messaging backend from scratch. The project was created and has been primarily maintained by South African developer JC Brand, with development beginning around 2012-2013. It is released under the Mozilla Public License version 2 (MPLv2), a permissive-but-copyleft license that allows commercial and non-commercial use, modification, and embedding while requiring that modifications to Converse's own source files remain open. The project is community-driven and sponsored through Open Collective and corporate backers rather than being a venture-funded startup; there is no company behind it in the traditional sense, and it has no per-seat or subscription pricing because the software itself is entirely free to self-host and use. Architecturally, Converse.js is a single-page application built with a plugin architecture (based on the pluggable.js library) that lets developers enable or disable features and write custom extensions. It ships with a full-page chat application out of the box but is most commonly deployed in one of three modes: an overlaid chat bubble similar to a customer-support widget, an embedded widget placed inside an existing page layout, or a standalone full-page messaging client. Because XMPP is a federated, open protocol (the same technology underlying WhatsApp's original architecture and Jitsi), Converse.js works with any compliant server implementation, including popular self-hosted options such as ejabberd, Prosody, and Openfire, as well as hosted XMPP providers. Key differentiators include first-class support for modern XMPP Extension Protocols (XEPs): OMEMO end-to-end encryption (XEP-0384) for private conversations and encrypted file/media sharing (XEP-0454), message styling (XEP-0393, Markdown-like formatting), message correction and retraction, moderator tools for group chats, message carbons and archive management (MAM) for multi-device history sync, and push notification support. The interface has been translated into more than 40 languages by community contributors, making it suitable for international deployments. Converse.js targets a technical audience: developers and organizations who want to self-host a chat feature rather than depend on a proprietary SaaS messaging vendor, particularly those already running or willing to run XMPP infrastructure. Typical use cases include embedding live chat/support widgets on websites, building internal team communication tools on top of self-hosted infrastructure, powering community or forum chat rooms, and providing a privacy-respecting alternative to closed messaging platforms for NGOs, cooperatives, and privacy-focused organizations. Because it is open protocol and open source end-to-end (client and, optionally, server), it appeals strongly to users who prioritize data sovereignty, self-hosting, and avoiding vendor lock-in — a very different value proposition from closed, hosted chat widgets like Intercom or Crisp, or from centralized messaging platforms like Slack or Discord. Within the XMPP ecosystem specifically, Converse.js competes with other web-based XMPP clients such as Movim, JSXC, and Candy Chat, though Converse is generally regarded as the most actively maintained and feature-complete browser-based option. More broadly, it is sometimes evaluated alongside other self-hostable, protocol-based chat systems such as Matrix/Element (which uses the Matrix protocol rather than XMPP) and Rocket.Chat. Deployment is lightweight: Converse.js can be dropped into a page via a script tag and a small configuration object specifying the XMPP connection endpoint (BOSH or WebSocket), authentication method (including anonymous login support for public chat rooms), and which plugins to enable — there is no build step or backend server required for the client itself, only an XMPP server to connect to. A companion project, converse-desktop, wraps the web client in Electron to provide native-feeling desktop apps for macOS, Windows, and Linux. Because Converse.js is not a company, it has no funding history, revenue model, headquarters, or enterprise sales process; its sustainability comes from GitHub sponsorships, Open Collective donations, and paid support/customization arrangements JC Brand and contributors offer on a freelance basis. For a directory or comparison context, Converse.js should be positioned as the leading open-source, self-hosted browser chat client for the XMPP protocol — a developer tool rather than a turnkey SaaS product — appealing to teams that want full control over their messaging data and infrastructure and are comfortable running or provisioning an XMPP server alongside it. In practice, Converse.js is frequently referenced in self-hosting and homelab communities (such as discussions on the Cloudron app platform forums) as one of the easiest ways to add a chat feature to a self-managed application stack, and step-by-step deployment guides exist for pairing it with popular hosting platforms. It supports anonymous, credential-free logins for public multi-user chat rooms, which makes it viable as a lightweight, ephemeral support-chat widget in addition to persistent, authenticated one-on-one messaging. Because the client speaks the open XMPP protocol over either BOSH (long-polling HTTP) or native WebSocket connections, it can be pointed at virtually any XMPP deployment without vendor-specific client code, which is a structural advantage over closed, single-vendor chat widget SDKs whose client libraries only work with that vendor's backend.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '6b2670c3-5248-4140-a4b2-ade8ee34ed2b';

