-- ── Coolify ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Coolify is an open-source, self-hostable PaaS alternative to Heroku, Vercel, and Netlify for deploying apps, databases, and services on your own servers.$q$, short_description),
  pricing_model = COALESCE($q$Free/Open Source$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2021, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE($q$Székesfehérvár, Hungary$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Coolify: Self-Hosted Open-Source PaaS Platform$q$, seo_title),
  seo_meta_description = COALESCE($q$Coolify is a free, open-source, self-hostable alternative to Heroku, Vercel, and Netlify for deploying apps, databases, and 280+ services on your servers.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Coolify is an open-source, self-hostable platform-as-a-service (PaaS) that lets developers deploy static sites, full-stack applications, databases, and pre-packaged one-click services onto their own servers, positioning itself as a self-hosted alternative to Heroku, Vercel, and Netlify. It was created by Hungarian developer Andras Bacsai, who started Coolify as a side project in 2021 during the early pandemic period and eventually left full-time employment to work on it, growing it into what is widely regarded as the most popular self-hosted PaaS tool in the open-source space. The project is developed by coolLabs Solutions Kft., a bootstrapped, independent company based in Székesfehérvár, Hungary, that has taken no venture capital funding and has no American parent company, giving it full control over its roadmap and business model. Coolify's core value proposition is operational simplicity combined with infrastructure ownership: a developer connects a Git repository (GitHub, GitLab, Bitbucket, or self-hosted Git), clicks deploy, and Coolify handles the rest of the deployment pipeline automatically. Under the hood, it builds applications using Nixpacks (an auto-detecting buildpack system) or a custom Dockerfile, configures a Traefik reverse proxy for routing, provisions automatic SSL/TLS certificates via Let's Encrypt, and can provision managed databases including PostgreSQL, MySQL, MariaDB, Redis, and MongoDB directly within the platform. It supports preview deployments tied to Git branches or pull requests, scheduled backups to any S3-compatible object storage, environment variable and secrets management, and a marketplace of more than 280 one-click service templates covering popular open-source tools (analytics platforms, CMSs, databases, monitoring stacks, and more) that can be deployed with a single click rather than manual Docker Compose configuration. The entire platform is released under the Apache 2.0 license and is completely free to self-host, with no artificial feature gating, no user or team caps, and no trial period restrictions — the full product, including all 280+ templates, unlimited servers, and unlimited team members, is available at zero software cost. The only expense in self-hosting is the underlying infrastructure itself: Coolify runs on Docker and can manage any number of connected VPS or bare-metal servers from providers such as Hetzner, DigitalOcean, AWS, or Linode, typically costing between roughly $5 and $25 per month depending on server size and provider. For teams that don't want to self-host the Coolify control plane itself, the company also offers Coolify Cloud, a paid managed version of the orchestration layer (not the application hosting itself) starting at $5 per month for two connected servers, with additional servers priced around $3 per month each and roughly a 20% discount for annual billing; customers using Cloud still bring and pay for their own underlying servers from any provider, with Coolify Cloud managing the coordination, dashboard, and deployment automation across them. On the self-hosted edition, teams and team members are unlimited at no additional cost, letting organizations create separate teams per client or project with distinct server access and permissions within a single Coolify instance; on Coolify Cloud, each additional team generally requires its own separate Cloud subscription. Coolify's target users are developers, small teams, agencies, and self-hosting enthusiasts who want the developer experience of a modern PaaS (git-push deploys, automatic HTTPS, managed databases, preview environments) without paying per-app or per-usage fees to a commercial cloud platform, and without giving up control of where their application data and infrastructure physically reside. This makes it especially popular with indie hackers, bootstrapped startups, digital agencies managing many client projects, and organizations with data-residency or cost-control concerns about hyperscale cloud PaaS pricing. In the competitive landscape, Coolify's closest peers are other self-hosted PaaS and deployment orchestration tools such as CapRover, Dokku, and Sealos, as well as commercial managed platforms it explicitly positions against — Heroku, Vercel, Netlify, and Railway — the key distinction being that Coolify's core software is free and runs on infrastructure the user owns, rather than usage-metered infrastructure owned by the vendor. Notable facts include Coolify's rapid organic growth almost entirely through open-source community adoption and word of mouth rather than paid marketing, its status as a bootstrapped, VC-free company at a time when many competing infrastructure startups are venture-funded, and its reputation within the self-hosting and homelab community as one of the most polished and actively developed projects in that space, with frequent releases (Coolify v4 introduced substantial architecture and UI improvements over earlier major versions). For a SaaS directory audience, Coolify should be framed as a free, open-source, developer-first deployment platform aimed at anyone who wants Heroku-like or Vercel-like ease of deployment while retaining full ownership of their servers and data, with an optional low-cost Cloud tier for teams that want a managed control plane without giving up server ownership. Coolify's project sustainability comes from a mix of Coolify Cloud subscription revenue, Open Collective donations, and GitHub sponsorships, a funding model that mirrors other successful bootstrapped open-source infrastructure projects rather than the venture-backed 'open core' model used by some competitors. The coolLabs team publishes its roadmap and contributor list openly, and the project has built a reputation for shipping frequent releases and responding quickly to community-reported issues, which is frequently cited as a differentiator versus other self-hosted PaaS tools that see slower release cadences. Coolify's growing marketplace of one-click templates is community-contributed as well as maintained by the core team, meaning the catalog of deployable services continues to expand as the self-hosting community adds new templates.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '005bfac7-53dd-49b7-9c17-ef452a208620';

