INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6b2670c3-5248-4140-a4b2-ade8ee34ed2b', $q$OMEMO end-to-end encryption$q$, $q$Encrypts one-on-one chats and shared files using the OMEMO protocol (XEP-0384/XEP-0454) for private, device-verified conversations.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6b2670c3-5248-4140-a4b2-ade8ee34ed2b', $q$Multi-user chat rooms$q$, $q$Full support for XMPP MUC group chats, including moderator tools, room configuration, and member management.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6b2670c3-5248-4140-a4b2-ade8ee34ed2b', $q$Plugin architecture$q$, $q$Built on pluggable.js so developers can enable, disable, or write custom plugins to extend or trim functionality.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6b2670c3-5248-4140-a4b2-ade8ee34ed2b', $q$Flexible embedding modes$q$, $q$Runs as an overlaid chat bubble, an inline embedded widget, or a full-page standalone chat application.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6b2670c3-5248-4140-a4b2-ade8ee34ed2b', $q$Broad server compatibility$q$, $q$Works with any standards-compliant XMPP server, including self-hosted ejabberd, Prosody, and Openfire deployments.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6b2670c3-5248-4140-a4b2-ade8ee34ed2b', $q$Message history sync$q$, $q$Uses Message Archive Management (MAM) to sync conversation history across multiple logged-in devices.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6b2670c3-5248-4140-a4b2-ade8ee34ed2b', $q$Message editing and moderation$q$, $q$Supports message correction, retraction, and moderator-level message removal in group chats.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6b2670c3-5248-4140-a4b2-ade8ee34ed2b', $q$45+ language translations$q$, $q$Community-translated UI supporting dozens of languages for international deployments.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6b2670c3-5248-4140-a4b2-ade8ee34ed2b', $q$Completely free and open source with no licensing fees, seat limits, or vendor lock-in$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6b2670c3-5248-4140-a4b2-ade8ee34ed2b', $q$Full data sovereignty — self-host both the client and the XMPP server$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6b2670c3-5248-4140-a4b2-ade8ee34ed2b', $q$Strong encryption support via OMEMO for private, secure conversations$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6b2670c3-5248-4140-a4b2-ade8ee34ed2b', $q$Actively maintained with a mature plugin ecosystem and wide XMPP server compatibility$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6b2670c3-5248-4140-a4b2-ade8ee34ed2b', $q$Requires access to or setup of an XMPP server, which adds operational overhead compared to turnkey SaaS chat widgets$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6b2670c3-5248-4140-a4b2-ade8ee34ed2b', $q$No official commercial support, SLA, or enterprise account management$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6b2670c3-5248-4140-a4b2-ade8ee34ed2b', $q$Smaller ecosystem and community than mainstream hosted chat platforms$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6b2670c3-5248-4140-a4b2-ade8ee34ed2b', $q$UI and feature set are geared toward developers, requiring configuration work rather than a no-code setup$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6b2670c3-5248-4140-a4b2-ade8ee34ed2b', $q$Is Converse.js free to use?$q$, $q$Yes. Converse.js is fully open source under the Mozilla Public License v2 and free to use, self-host, and modify with no subscription cost.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6b2670c3-5248-4140-a4b2-ade8ee34ed2b', $q$Do I need my own XMPP server to use Converse.js?$q$, $q$Yes. Converse.js is only the browser-based client; it must connect to a standards-compliant XMPP server such as ejabberd, Prosody, Openfire, or a hosted XMPP provider.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6b2670c3-5248-4140-a4b2-ade8ee34ed2b', $q$Does Converse.js support encrypted messaging?$q$, $q$Yes. It supports OMEMO end-to-end encryption for one-on-one chats and encrypted file sharing via XEP-0454.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6b2670c3-5248-4140-a4b2-ade8ee34ed2b', $q$Can Converse.js be embedded as a support widget?$q$, $q$Yes. It can run as an overlaid chat bubble or embedded widget in addition to a full-page chat application.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6b2670c3-5248-4140-a4b2-ade8ee34ed2b', $q$Is there a desktop app version?$q$, $q$Yes, via the companion converse-desktop project, which wraps the web client in Electron for macOS, Windows, and Linux.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6b2670c3-5248-4140-a4b2-ade8ee34ed2b', $q$Who maintains Converse.js?$q$, $q$It is maintained primarily by creator JC Brand along with community contributors, funded through Open Collective and sponsorships rather than a commercial company.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('6b2670c3-5248-4140-a4b2-ade8ee34ed2b', $q$Self-hosted customer support chat$q$, $q$Organizations embed Converse.js as a chat widget backed by their own XMPP server to offer live support without depending on a third-party SaaS vendor.$q$, $q$Developers and privacy-conscious support teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('6b2670c3-5248-4140-a4b2-ade8ee34ed2b', $q$Internal team or community messaging$q$, $q$Teams and online communities deploy Converse.js as a full-page chat app for internal communication or public community chat rooms.$q$, $q$Open-source communities, NGOs, and cooperatives$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('6b2670c3-5248-4140-a4b2-ade8ee34ed2b', $q$Federated, privacy-first messaging$q$, $q$Privacy-focused organizations use Converse.js with self-hosted XMPP infrastructure to keep full control over message data and avoid vendor lock-in.$q$, $q$Privacy advocates and data-sovereignty-focused organizations$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('6b2670c3-5248-4140-a4b2-ade8ee34ed2b', $q$Open Source$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Full source code under MPLv2","Self-hosted, unlimited use","Plugin architecture and full feature set","Community support"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('6b2670c3-5248-4140-a4b2-ade8ee34ed2b', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Converse.js is a free, open-source chat client for the XMPP (Jabber) protocol that runs entirely in the browser. Rather than shipping a hosted messaging service, it gives developers a JavaScript library they can embed on any website and connect to a standards-compliant XMPP server they control.$q$, $q$First developed around 2012-2013 by JC Brand and released under the Mozilla Public License v2, Converse.js has grown into the most actively maintained web-based XMPP client available, with a plugin architecture, translations into 40+ languages, and support for modern encryption and messaging extensions.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('6b2670c3-5248-4140-a4b2-ade8ee34ed2b', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Converse.js supports one-on-one chat, multi-user chat rooms (MUC), OMEMO end-to-end encryption for both text and shared files, message correction and retraction, moderator and admin tooling for group chats, and multi-device history sync through Message Archive Management (MAM).$q$, $q$It can be deployed as an overlaid chat bubble, an embedded widget inside a page, or a full-page standalone messaging app, and it works with any XMPP server, including self-hosted options like ejabberd, Prosody, and Openfire.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('6b2670c3-5248-4140-a4b2-ade8ee34ed2b', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Converse.js is completely free to use, modify, and self-host under the MPLv2 license. There are no subscription tiers, seat limits, or paid upgrades for the client itself; costs are limited to whatever infrastructure is used to run the XMPP server it connects to.$q$, $q$Because the project is community-maintained rather than a commercial company, support is available through community channels, GitHub issues, and paid freelance arrangements with contributors rather than a formal enterprise sales or support tier.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('6b2670c3-5248-4140-a4b2-ade8ee34ed2b', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('6b2670c3-5248-4140-a4b2-ade8ee34ed2b', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('6b2670c3-5248-4140-a4b2-ade8ee34ed2b', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('6b2670c3-5248-4140-a4b2-ade8ee34ed2b', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fe42bb0d-0769-4be9-8240-7ea8c6d5d159', $q$Reactive document database$q$, $q$Queries automatically re-run and push updated results to connected clients whenever underlying data changes, without manual subscription code.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fe42bb0d-0769-4be9-8240-7ea8c6d5d159', $q$Serverless TypeScript functions$q$, $q$Application logic is written as queries, mutations, and actions deployed directly on Convex's managed infrastructure.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fe42bb0d-0769-4be9-8240-7ea8c6d5d159', $q$ACID-transactional writes$q$, $q$Mutations execute as atomic, consistent transactions, avoiding the race conditions common in eventually-consistent backends.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fe42bb0d-0769-4be9-8240-7ea8c6d5d159', $q$Built-in file storage$q$, $q$Store and serve files directly from Convex without provisioning a separate object storage service.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fe42bb0d-0769-4be9-8240-7ea8c6d5d159', $q$Vector and full-text search$q$, $q$Native search capabilities support AI-powered retrieval-augmented generation (RAG) and semantic search workloads.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fe42bb0d-0769-4be9-8240-7ea8c6d5d159', $q$Scheduled functions and cron jobs$q$, $q$Run background and time-based jobs natively within the platform.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fe42bb0d-0769-4be9-8240-7ea8c6d5d159', $q$End-to-end TypeScript type safety$q$, $q$Types flow from the database schema through functions to the client for compile-time safety.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fe42bb0d-0769-4be9-8240-7ea8c6d5d159', $q$Open-source core engine$q$, $q$The convex-backend engine is Apache 2.0 licensed and available for self-hosting.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('fe42bb0d-0769-4be9-8240-7ea8c6d5d159', $q$Eliminates the need to hand-build real-time sync, caching, and subscription logic$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('fe42bb0d-0769-4be9-8240-7ea8c6d5d159', $q$Strong TypeScript-first developer experience with end-to-end type safety$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('fe42bb0d-0769-4be9-8240-7ea8c6d5d159', $q$Bundles database, functions, auth, storage, and search into one platform$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('fe42bb0d-0769-4be9-8240-7ea8c6d5d159', $q$Core backend is open source, giving an escape hatch from full vendor lock-in$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('fe42bb0d-0769-4be9-8240-7ea8c6d5d159', $q$Per-developer seat pricing on the Professional plan can add up for larger teams$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('fe42bb0d-0769-4be9-8240-7ea8c6d5d159', $q$Newer platform with a smaller ecosystem and community than Firebase or Supabase$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('fe42bb0d-0769-4be9-8240-7ea8c6d5d159', $q$TypeScript/JavaScript-centric function model may not suit teams standardized on other backend languages$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('fe42bb0d-0769-4be9-8240-7ea8c6d5d159', $q$Enterprise-grade features like SSO and formal SLAs were still maturing at the time of research$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fe42bb0d-0769-4be9-8240-7ea8c6d5d159', $q$What is Convex used for?$q$, $q$Convex is a backend-as-a-service platform used to build real-time, data-driven web and mobile applications with a reactive database, serverless functions, auth, and storage in one system.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fe42bb0d-0769-4be9-8240-7ea8c6d5d159', $q$Is Convex open source?$q$, $q$The core Convex backend engine (convex-backend) is open source under the Apache 2.0 license and can be self-hosted, though most users run the managed cloud service.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fe42bb0d-0769-4be9-8240-7ea8c6d5d159', $q$How much does Convex cost?$q$, $q$Convex has a free, pay-as-you-go Starter plan and a Professional plan priced around $25 per developer per month with higher resource allowances; an Enterprise tier with custom pricing is also available.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fe42bb0d-0769-4be9-8240-7ea8c6d5d159', $q$What languages does Convex support?$q$, $q$Convex functions are written in TypeScript or JavaScript, with official client libraries for React, Next.js, React Native, and other JavaScript frameworks.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fe42bb0d-0769-4be9-8240-7ea8c6d5d159', $q$How is Convex different from Firebase or Supabase?$q$, $q$Convex emphasizes automatic reactivity without manual subscription code, ACID-transactional writes, and a TypeScript-native function model, whereas Firebase and Supabase use different data and consistency models.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fe42bb0d-0769-4be9-8240-7ea8c6d5d159', $q$Who founded Convex?$q$, $q$Convex was founded in 2021 by Jamie Turner, James Cowling, and Sujay Jayakar, former Dropbox engineers who worked on large-scale storage and database systems.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('fe42bb0d-0769-4be9-8240-7ea8c6d5d159', $q$Real-time collaborative apps$q$, $q$Teams build collaborative tools, dashboards, and multiplayer experiences that need instant UI updates without manual WebSocket plumbing.$q$, $q$Full-stack developers building SaaS products$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('fe42bb0d-0769-4be9-8240-7ea8c6d5d159', $q$AI agent and RAG applications$q$, $q$Developers use Convex's vector search and reactive state to build AI agents and retrieval-augmented generation apps with persistent, synchronized state.$q$, $q$AI/ML application developers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('fe42bb0d-0769-4be9-8240-7ea8c6d5d159', $q$Rapid MVP and startup backend$q$, $q$Early-stage startups use Convex to avoid provisioning separate database, auth, and API infrastructure while iterating quickly.$q$, $q$Startup founders and indie developers$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('fe42bb0d-0769-4be9-8240-7ea8c6d5d159', $q$Free (Starter)$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Pay-as-you-go, scale-to-zero","Generous built-in function call and storage limits","Up to 6 team members","Community support"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('fe42bb0d-0769-4be9-8240-7ea8c6d5d159', $q$Professional$q$, $q$$25/developer/month$q$, $q$Monthly per developer$q$, NULL, $q$["Higher built-in resource allowances","Lower per-unit overage rates","Larger database storage, I/O, and egress limits","Priority support"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('fe42bb0d-0769-4be9-8240-7ea8c6d5d159', $q$Enterprise$q$, $q$Custom$q$, $q$Annual/custom$q$, NULL, $q$["Single sign-on (SSO)","Advanced telemetry and auditing","Compliance support","Custom SLAs"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('fe42bb0d-0769-4be9-8240-7ea8c6d5d159', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Convex is a reactive backend-as-a-service platform that bundles a real-time document database, serverless TypeScript functions, authentication, file storage, and search into a single managed system. It was founded in 2021 by ex-Dropbox engineers Jamie Turner, James Cowling, and Sujay Jayakar and is headquartered in San Francisco.$q$, $q$Instead of manually wiring together a database, an API layer, and real-time subscriptions, developers write queries and mutations as TypeScript functions; Convex automatically keeps connected clients in sync whenever the underlying data changes.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('fe42bb0d-0769-4be9-8240-7ea8c6d5d159', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Core features include reactive queries that auto-update connected UIs, ACID-transactional mutations, scheduled functions and cron jobs, built-in file storage, vector and full-text search for AI/RAG use cases, and end-to-end TypeScript type safety from schema to client.$q$, $q$Convex integrates with popular auth providers like Clerk and Auth0, and its core backend engine is open source under Apache 2.0, giving teams the option to self-host while most use the managed cloud service.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('fe42bb0d-0769-4be9-8240-7ea8c6d5d159', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Convex offers a free, pay-as-you-go Starter plan with generous built-in resource limits ideal for prototypes and small projects, and a Professional plan priced around $25 per developer per month that unlocks larger resource allowances and lower usage overage rates.$q$, $q$An Enterprise plan aimed at larger organizations, with SSO, compliance features, and SLAs, is available for teams with advanced requirements, and qualifying startups can apply for a year of free Professional access.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('fe42bb0d-0769-4be9-8240-7ea8c6d5d159', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('fe42bb0d-0769-4be9-8240-7ea8c6d5d159', 'd5f794d8-1509-49c9-ac15-6834dce260e9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('fe42bb0d-0769-4be9-8240-7ea8c6d5d159', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('fe42bb0d-0769-4be9-8240-7ea8c6d5d159', '610c2598-d057-4727-bf3b-e907b0daed7f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('fe42bb0d-0769-4be9-8240-7ea8c6d5d159', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('fe42bb0d-0769-4be9-8240-7ea8c6d5d159', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('eb460c74-dce8-4856-9dc3-61f824bd3a75', $q$Automatic retries with backoff$q$, $q$Failed webhook deliveries are automatically retried using configurable retry and backoff policies.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('eb460c74-dce8-4856-9dc3-61f824bd3a75', $q$Rate limiting and circuit breaking$q$, $q$Protects downstream endpoints from being overwhelmed and automatically backs off from consistently failing endpoints.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('eb460c74-dce8-4856-9dc3-61f824bd3a75', $q$Static outbound IPs$q$, $q$Provides fixed IP addresses so customers can safely allow-list Convoy's outbound traffic.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('eb460c74-dce8-4856-9dc3-61f824bd3a75', $q$Rolling signing secrets$q$, $q$Supports rotating webhook signing secrets to verify payload authenticity without downtime during rotation.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('eb460c74-dce8-4856-9dc3-61f824bd3a75', $q$Event replay and debugging$q$, $q$Lets engineers inspect, replay, and debug individual webhook events for troubleshooting.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('eb460c74-dce8-4856-9dc3-61f824bd3a75', $q$Inbound and outbound gateway$q$, $q$Handles both sending webhooks to customers and securely receiving/routing webhooks from third-party providers.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('eb460c74-dce8-4856-9dc3-61f824bd3a75', $q$Self-hosted or managed cloud$q$, $q$Deployable as a free, self-hosted open-source instance or as a fully managed Convoy Cloud service.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('eb460c74-dce8-4856-9dc3-61f824bd3a75', $q$Built in Go$q$, $q$Written in Go for high throughput and reliability, consistent with infrastructure tools like Kubernetes and Prometheus.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('eb460c74-dce8-4856-9dc3-61f824bd3a75', $q$Free, open-source self-hosted option gives full control over webhook infrastructure and data$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('eb460c74-dce8-4856-9dc3-61f824bd3a75', $q$Purpose-built reliability features (retries, rate limiting, circuit breaking) reduce the need for custom in-house solutions$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('eb460c74-dce8-4856-9dc3-61f824bd3a75', $q$Handles both outbound and inbound webhook use cases in a single gateway$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('eb460c74-dce8-4856-9dc3-61f824bd3a75', $q$Transparent, accessible Cloud pricing for small teams alongside enterprise options for scale$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('eb460c74-dce8-4856-9dc3-61f824bd3a75', $q$Licensing has shifted from MPL 2.0 toward the Elastic License 2.0 for some components, which may affect certain commercial redistribution use cases$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('eb460c74-dce8-4856-9dc3-61f824bd3a75', $q$Smaller company and ecosystem compared to some dedicated webhook competitors$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('eb460c74-dce8-4856-9dc3-61f824bd3a75', $q$Self-hosting requires operational overhead (infrastructure, upgrades, scaling) if the managed Cloud option is not used$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('eb460c74-dce8-4856-9dc3-61f824bd3a75', $q$Enterprise pricing requires a sales conversation rather than transparent published rates$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('eb460c74-dce8-4856-9dc3-61f824bd3a75', $q$Is Convoy free to use?$q$, $q$Yes. Convoy's core engine is open source and free to self-host. A managed Convoy Cloud plan starts at roughly $99/month, and an Enterprise tier is available for high-volume customers.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('eb460c74-dce8-4856-9dc3-61f824bd3a75', $q$What is Convoy used for?$q$, $q$Convoy is a webhooks gateway used to reliably send outbound webhook events to customers and to securely receive and route inbound webhooks from third-party providers.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('eb460c74-dce8-4856-9dc3-61f824bd3a75', $q$Is Convoy open source?$q$, $q$Yes, Convoy has always shipped its core as open source with a public roadmap, though some newer components use the Elastic License 2.0 rather than a fully permissive license.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('eb460c74-dce8-4856-9dc3-61f824bd3a75', $q$What programming language is Convoy built in?$q$, $q$Convoy is written in Go, chosen for performance and reliability at the scale required for infrastructure software.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('eb460c74-dce8-4856-9dc3-61f824bd3a75', $q$Who founded Convoy?$q$, $q$Convoy was founded in 2021 by Subomi Oluwalana and Emmanuel Aina, and it went through Y Combinator's Winter 2022 (W22) batch.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('eb460c74-dce8-4856-9dc3-61f824bd3a75', $q$How is Convoy different from the trucking company Convoy?$q$, $q$This Convoy (getconvoy.io) is an unrelated, separate open-source webhooks infrastructure company; it has no connection to the digital freight/trucking network of the same name.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('eb460c74-dce8-4856-9dc3-61f824bd3a75', $q$SaaS platform webhook delivery$q$, $q$SaaS companies use Convoy to reliably deliver outbound webhook notifications to their own customers' endpoints with retries and monitoring.$q$, $q$Platform and backend engineering teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('eb460c74-dce8-4856-9dc3-61f824bd3a75', $q$Secure inbound webhook ingestion$q$, $q$Companies use Convoy to receive webhooks from providers like Stripe or Twilio and route them internally without exposing internal services to the public internet.$q$, $q$Fintech and e-commerce engineering teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('eb460c74-dce8-4856-9dc3-61f824bd3a75', $q$Self-hosted compliance-driven deployments$q$, $q$Organizations with data residency or compliance requirements self-host Convoy's open-source engine to keep webhook event data within their own infrastructure.$q$, $q$Regulated industries and security-conscious engineering teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('eb460c74-dce8-4856-9dc3-61f824bd3a75', $q$Community (Self-Hosted)$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Open-source core engine","Self-hosted deployment","Retries, rate limiting, circuit breaking","Community support"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('eb460c74-dce8-4856-9dc3-61f824bd3a75', $q$Cloud Pro$q$, $q$From $99/month$q$, $q$Monthly$q$, NULL, $q$["Fully managed cloud hosting","Usage-based pricing","Static outbound IPs","Event replay and debugging tools"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('eb460c74-dce8-4856-9dc3-61f824bd3a75', $q$Enterprise$q$, $q$Custom$q$, $q$Custom$q$, NULL, $q$["For 20M+ events/month","Dedicated customer success team","Licensed self-hosted Premium tier available","Custom SLAs"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('eb460c74-dce8-4856-9dc3-61f824bd3a75', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Convoy is an open-source, cloud-native webhooks gateway that helps engineering teams reliably send and receive webhook events at scale. Built in Go and founded in 2021 by Subomi Oluwalana and Emmanuel Aina, Convoy went through Y Combinator's W22 batch and is headquartered in San Francisco with engineering based partly in Lagos, Nigeria.$q$, $q$The platform sits at the edge of a company's infrastructure, ingesting outbound events from internal services and delivering them to external endpoints, while also routing inbound webhooks from third-party providers to internal systems without exposing them directly to the public internet.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('eb460c74-dce8-4856-9dc3-61f824bd3a75', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Convoy provides automatic retries with configurable backoff, per-endpoint rate limiting, circuit breaking, static outbound IPs, rolling signing secrets, and event replay and debugging tools to make webhook delivery reliable and observable.$q$, $q$It is available as a free, self-hosted Community edition, a managed Convoy Cloud offering, and an Enterprise Partnership Program for organizations processing very high volumes of events.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('eb460c74-dce8-4856-9dc3-61f824bd3a75', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$The core Convoy engine is free and open source for self-hosting. Convoy Cloud, the managed offering, uses transparent usage-based pricing with a Pro plan starting around $99 per month for small teams and startups.$q$, $q$Organizations sending more than roughly 20 million webhook events per month qualify for Convoy's Enterprise Partnership Program, which includes custom pricing and dedicated customer success support.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('eb460c74-dce8-4856-9dc3-61f824bd3a75', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('eb460c74-dce8-4856-9dc3-61f824bd3a75', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('eb460c74-dce8-4856-9dc3-61f824bd3a75', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('eb460c74-dce8-4856-9dc3-61f824bd3a75', 'd5f794d8-1509-49c9-ac15-6834dce260e9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('eb460c74-dce8-4856-9dc3-61f824bd3a75', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('005bfac7-53dd-49b7-9c17-ef452a208620', $q$One-click Git deployments$q$, $q$Connect a GitHub, GitLab, or Bitbucket repository and deploy automatically using Nixpacks auto-detection or a custom Dockerfile.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('005bfac7-53dd-49b7-9c17-ef452a208620', $q$Automatic SSL and reverse proxy$q$, $q$Traefik reverse proxy configuration and Let's Encrypt SSL certificates are provisioned automatically for every deployment.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('005bfac7-53dd-49b7-9c17-ef452a208620', $q$Managed database provisioning$q$, $q$Deploy PostgreSQL, MySQL, MariaDB, Redis, or MongoDB databases directly within Coolify without manual setup.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('005bfac7-53dd-49b7-9c17-ef452a208620', $q$280+ one-click service templates$q$, $q$A marketplace of pre-configured open-source services and tools that deploy with a single click instead of manual Docker Compose work.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('005bfac7-53dd-49b7-9c17-ef452a208620', $q$Preview deployments$q$, $q$Automatic preview environments tied to Git branches or pull requests for testing changes before merging.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('005bfac7-53dd-49b7-9c17-ef452a208620', $q$S3-compatible backups$q$, $q$Scheduled, automated backups to any S3-compatible object storage provider.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('005bfac7-53dd-49b7-9c17-ef452a208620', $q$Unlimited teams and servers (self-hosted)$q$, $q$Self-hosted installations support unlimited connected servers and unlimited team members at no extra cost.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('005bfac7-53dd-49b7-9c17-ef452a208620', $q$Multi-cloud server support$q$, $q$Connect and manage servers from Hetzner, DigitalOcean, AWS, or any provider that supports Docker.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('005bfac7-53dd-49b7-9c17-ef452a208620', $q$Fully free, open-source self-hosted edition under Apache 2.0 with no feature gating$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('005bfac7-53dd-49b7-9c17-ef452a208620', $q$Simple, Heroku-like developer experience while retaining full control over servers and data$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('005bfac7-53dd-49b7-9c17-ef452a208620', $q$Large marketplace of 280+ one-click service templates reduces manual configuration$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('005bfac7-53dd-49b7-9c17-ef452a208620', $q$Bootstrapped and independent, giving predictable long-term project direction without VC pressure$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('005bfac7-53dd-49b7-9c17-ef452a208620', $q$Self-hosting requires managing your own server infrastructure and updates$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('005bfac7-53dd-49b7-9c17-ef452a208620', $q$Smaller support organization compared to large commercial cloud platforms$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('005bfac7-53dd-49b7-9c17-ef452a208620', $q$Coolify Cloud requires a separate subscription per additional team$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('005bfac7-53dd-49b7-9c17-ef452a208620', $q$Advanced enterprise features (formal SLAs, dedicated support contracts) are limited given its bootstrapped, community-driven nature$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('005bfac7-53dd-49b7-9c17-ef452a208620', $q$Is Coolify free?$q$, $q$Yes. Self-hosted Coolify is free forever under the Apache 2.0 license with no feature limits, user caps, or trial period. You only pay for your own server infrastructure.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('005bfac7-53dd-49b7-9c17-ef452a208620', $q$What is Coolify Cloud?$q$, $q$Coolify Cloud is a paid, managed version of Coolify's orchestration/control-plane layer starting at $5/month for two connected servers; it manages your own servers from providers like Hetzner or DigitalOcean rather than hosting your apps itself.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('005bfac7-53dd-49b7-9c17-ef452a208620', $q$What can I deploy with Coolify?$q$, $q$Coolify can deploy static sites, full-stack applications, managed databases (PostgreSQL, MySQL, MariaDB, Redis, MongoDB), and 280+ one-click open-source service templates.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('005bfac7-53dd-49b7-9c17-ef452a208620', $q$Who created Coolify?$q$, $q$Coolify was created by Andras Bacsai in 2021 and is developed by coolLabs Solutions Kft., a bootstrapped, independent Hungarian company with no venture capital funding.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('005bfac7-53dd-49b7-9c17-ef452a208620', $q$How is Coolify different from Heroku or Vercel?$q$, $q$Coolify runs on servers you own and is free open-source software, whereas Heroku and Vercel are proprietary managed platforms that host your application on their own infrastructure and charge usage-based fees.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('005bfac7-53dd-49b7-9c17-ef452a208620', $q$Does Coolify support preview deployments?$q$, $q$Yes, Coolify automatically creates preview deployments tied to Git branches or pull requests.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('005bfac7-53dd-49b7-9c17-ef452a208620', $q$Self-hosted app deployment for indie developers$q$, $q$Solo developers and indie hackers use Coolify to deploy side projects and SaaS apps to low-cost VPS providers without paying platform usage fees.$q$, $q$Indie developers and bootstrapped founders$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('005bfac7-53dd-49b7-9c17-ef452a208620', $q$Agency multi-client hosting$q$, $q$Digital agencies use Coolify's unlimited teams and servers to host and manage many client projects from a single self-hosted control plane.$q$, $q$Web development and digital agencies$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('005bfac7-53dd-49b7-9c17-ef452a208620', $q$Data-residency and cost-sensitive infrastructure$q$, $q$Organizations with data-residency requirements or cost concerns about hyperscale PaaS pricing self-host Coolify to keep data on their own chosen infrastructure.$q$, $q$Regulated or cost-conscious engineering teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('005bfac7-53dd-49b7-9c17-ef452a208620', $q$Self-Hosted$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Apache 2.0 licensed, full feature set","Unlimited servers and team members","280+ one-click service templates","Community support"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('005bfac7-53dd-49b7-9c17-ef452a208620', $q$Coolify Cloud$q$, $q$$5/month (2 servers)$q$, $q$Monthly (annual discount ~20%)$q$, NULL, $q$["Managed orchestration control plane","~$3/month per additional connected server","Bring your own servers from any provider","Simplified dashboard management"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('005bfac7-53dd-49b7-9c17-ef452a208620', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Coolify is an open-source, self-hostable platform-as-a-service that lets developers deploy applications, databases, and pre-packaged services to their own servers with the simplicity of Heroku, Vercel, or Netlify. It was created by Andras Bacsai as a side project in 2021 and is now developed by coolLabs Solutions Kft., a bootstrapped, VC-free company based in Hungary.$q$, $q$Users connect a Git repository and deploy, with Coolify automatically handling builds (via Nixpacks or a custom Dockerfile), reverse proxy configuration through Traefik, and automatic SSL via Let's Encrypt on servers the user owns.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('005bfac7-53dd-49b7-9c17-ef452a208620', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Coolify provisions managed databases (PostgreSQL, MySQL, MariaDB, Redis, MongoDB), supports Git-branch preview deployments, automated backups to S3-compatible storage, and a marketplace of 280+ one-click service templates for popular open-source tools.$q$, $q$The self-hosted edition is released under the Apache 2.0 license with no feature gating, unlimited servers, and unlimited team members, making the full product free regardless of scale.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('005bfac7-53dd-49b7-9c17-ef452a208620', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Self-hosted Coolify is free forever; the only cost is the underlying server infrastructure, which typically runs $5-$25/month depending on provider and size.$q$, $q$Coolify Cloud, a managed version of the orchestration layer, starts at $5/month for two connected servers, with additional servers priced around $3/month each and an annual billing discount of roughly 20%.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('005bfac7-53dd-49b7-9c17-ef452a208620', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('005bfac7-53dd-49b7-9c17-ef452a208620', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('005bfac7-53dd-49b7-9c17-ef452a208620', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('005bfac7-53dd-49b7-9c17-ef452a208620', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ca95321e-8259-4037-a292-11f90e6c3856', $q$Native Gmail integration$q$, $q$Automatically captures and logs email activity against the correct contact and company records directly inside Gmail.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ca95321e-8259-4037-a292-11f90e6c3856', $q$Google Calendar sync$q$, $q$Bidirectional sync between Copper and Google Calendar keeps meetings and events tied to CRM records automatically.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ca95321e-8259-4037-a292-11f90e6c3856', $q$Customizable sales pipelines$q$, $q$Configure deal stages and pipeline views tailored to a team's specific sales process.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ca95321e-8259-4037-a292-11f90e6c3856', $q$Workflow automation$q$, $q$Automates repetitive tasks and follow-ups to reduce manual data entry and keep deals moving.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ca95321e-8259-4037-a292-11f90e6c3856', $q$Chrome extension$q$, $q$Surfaces CRM context, contact history, and quick actions directly inside the Gmail inbox interface.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ca95321e-8259-4037-a292-11f90e6c3856', $q$Copper for Google Sheets$q$, $q$View and edit CRM data directly from a Google Sheets interface for teams that prefer spreadsheet workflows.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ca95321e-8259-4037-a292-11f90e6c3856', $q$Reporting and forecasting$q$, $q$Built-in dashboards track pipeline health, revenue forecasts, and team performance.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ca95321e-8259-4037-a292-11f90e6c3856', $q$Third-party integrations$q$, $q$Connects with Slack, Zoom, QuickBooks, and marketing automation tools via API and app marketplace.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ca95321e-8259-4037-a292-11f90e6c3856', $q$Deep, native integration with Gmail, Calendar, and the broader Google Workspace suite$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ca95321e-8259-4037-a292-11f90e6c3856', $q$Low learning curve for teams already working daily inside Gmail$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ca95321e-8259-4037-a292-11f90e6c3856', $q$Automatic activity capture significantly reduces manual data entry$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ca95321e-8259-4037-a292-11f90e6c3856', $q$Officially recommended CRM within the Google Workspace Marketplace$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ca95321e-8259-4037-a292-11f90e6c3856', $q$No permanent free plan, only a 14-day trial$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ca95321e-8259-4037-a292-11f90e6c3856', $q$Less deeply customizable than enterprise-grade CRMs like Salesforce$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ca95321e-8259-4037-a292-11f90e6c3856', $q$Best suited to Google Workspace users; less compelling for Microsoft 365-centric organizations$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ca95321e-8259-4037-a292-11f90e6c3856', $q$Contact and custom field limits on lower tiers may require upgrading as a business grows$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ca95321e-8259-4037-a292-11f90e6c3856', $q$How much does Copper CRM cost?$q$, $q$Copper's paid plans start at $23 per user per month (billed annually) for Basic, rising to $59/user/month for Professional and $99/user/month for Business; monthly billing is priced higher.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ca95321e-8259-4037-a292-11f90e6c3856', $q$Does Copper have a free plan?$q$, $q$No, Copper does not offer a permanent free plan, but it provides a 14-day free trial that doesn't require a credit card.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ca95321e-8259-4037-a292-11f90e6c3856', $q$Is Copper only for Google Workspace users?$q$, $q$Copper is purpose-built around native Gmail, Calendar, and Drive integration, so it delivers the most value to teams already using Google Workspace, though it can still function as a standalone CRM.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ca95321e-8259-4037-a292-11f90e6c3856', $q$What was Copper CRM previously called?$q$, $q$Copper was originally founded in 2013 as ProsperWorks and rebranded to Copper in 2018.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ca95321e-8259-4037-a292-11f90e6c3856', $q$How many contacts can Copper handle?$q$, $q$Contact limits vary by plan: 2,500 on Basic, 15,000 on Professional, and unlimited contacts on the Business plan.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ca95321e-8259-4037-a292-11f90e6c3856', $q$What are Copper's main competitors?$q$, $q$Copper is commonly compared to HubSpot CRM, Pipedrive, Streak, and Salesforce Essentials, with its main differentiator being native Google Workspace integration.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ca95321e-8259-4037-a292-11f90e6c3856', $q$Google Workspace-native sales teams$q$, $q$Sales teams already operating inside Gmail and Google Calendar adopt Copper to manage pipelines without switching context to a separate app.$q$, $q$SMB sales teams on Google Workspace$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ca95321e-8259-4037-a292-11f90e6c3856', $q$Relationship-driven B2B agencies$q$, $q$Agencies and consultancies use Copper's automatic activity capture to track client relationships with minimal manual logging.$q$, $q$Agencies and professional services firms$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ca95321e-8259-4037-a292-11f90e6c3856', $q$Low-friction CRM adoption for growing businesses$q$, $q$Small businesses that struggled with CRM adoption due to manual data entry use Copper's automation to improve rep compliance and pipeline visibility.$q$, $q$Growing small and mid-size businesses$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('ca95321e-8259-4037-a292-11f90e6c3856', $q$Basic$q$, $q$$23/user/month (annual) / $29/user/month (monthly)$q$, $q$Monthly or annual$q$, NULL, $q$["Up to 2,500 contacts","25 custom fields","Sales pipeline management","Task automation"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('ca95321e-8259-4037-a292-11f90e6c3856', $q$Professional$q$, $q$$59/user/month (annual) / $69/user/month (monthly)$q$, $q$Monthly or annual$q$, NULL, $q$["Up to 15,000 contacts","50 custom fields","Advanced automation","Enhanced reporting"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('ca95321e-8259-4037-a292-11f90e6c3856', $q$Business$q$, $q$$99/user/month (annual) / $134/user/month (monthly)$q$, $q$Monthly or annual$q$, NULL, $q$["Unlimited contacts","Full customization","Advanced reporting and forecasting","Broader integration options"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ca95321e-8259-4037-a292-11f90e6c3856', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Copper is a CRM built natively for Google Workspace, automatically capturing emails, meetings, and contacts from Gmail, Calendar, and Drive to reduce manual data entry. Originally founded in San Francisco in 2013 as ProsperWorks by Jon Lee, the company rebranded to Copper in 2018 and has since raised roughly $99.5 million in venture funding.$q$, $q$Copper is an officially recommended CRM in the Google Workspace Marketplace and reports serving more than 30,000 businesses, positioning itself as the CRM of choice for teams already living inside Gmail and Google Calendar.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ca95321e-8259-4037-a292-11f90e6c3856', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Copper automatically logs emails, calls, and calendar events against contact and company records, suggests new leads from email activity, and syncs bidirectionally with Google Contacts and Calendar via a Chrome extension.$q$, $q$It also provides customizable sales pipelines, task and workflow automation, forecasting and reporting dashboards, email templates, and a Copper CRM for Google Sheets integration.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ca95321e-8259-4037-a292-11f90e6c3856', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Copper offers three paid tiers with no permanent free plan but a 14-day, no-credit-card trial: Basic at $23/user/month (annual), Professional at $59/user/month (annual), and Business at $99/user/month (annual).$q$, $q$Monthly billing is available at higher per-user rates ($29, $69, and $134 respectively), with annual commitments saving up to roughly 26%.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('ca95321e-8259-4037-a292-11f90e6c3856', 'd5f794d8-1509-49c9-ac15-6834dce260e9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('ca95321e-8259-4037-a292-11f90e6c3856', '610c2598-d057-4727-bf3b-e907b0daed7f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('ca95321e-8259-4037-a292-11f90e6c3856', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('ca95321e-8259-4037-a292-11f90e6c3856', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3c515695-9a2f-4479-901f-6ca785a0e07c', $q$AI chat writing interface$q$, $q$Generate marketing copy, sales outreach, and business content on demand through a conversational chat interface.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3c515695-9a2f-4479-901f-6ca785a0e07c', $q$Brand Voice training$q$, $q$Trains the AI on a team's existing writing samples so generated content matches a consistent brand tone and style.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3c515695-9a2f-4479-901f-6ca785a0e07c', $q$Workflow automation$q$, $q$Chains multiple AI generation and data steps together to automate repeatable GTM tasks like outbound sequences and proposals.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3c515695-9a2f-4479-901f-6ca785a0e07c', $q$Multi-LLM access$q$, $q$Access to multiple leading large language models depending on plan tier, rather than being locked to a single model provider.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3c515695-9a2f-4479-901f-6ca785a0e07c', $q$API access and bulk workflows$q$, $q$Higher-tier plans expose API access and bulk workflow execution for embedding Copy.ai into internal tools and pipelines.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3c515695-9a2f-4479-901f-6ca785a0e07c', $q$Technology integrations$q$, $q$Connects with 20+ sales and marketing tools on Enterprise plans for embedding AI content generation into existing GTM stacks.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3c515695-9a2f-4479-901f-6ca785a0e07c', $q$Unlimited chat projects (paid tiers)$q$, $q$Paid plans remove word limits and allow unlimited organized chat projects for ongoing content work.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3c515695-9a2f-4479-901f-6ca785a0e07c', $q$Fullcast Propel integration$q$, $q$Following its 2025 acquisition, Copy.ai's AI execution layer is being integrated into Fullcast's broader Plan-to-Pay RevOps platform.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3c515695-9a2f-4479-901f-6ca785a0e07c', $q$Generous free tier lets individuals and small teams try the product with no credit card required$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3c515695-9a2f-4479-901f-6ca785a0e07c', $q$Brand Voice training helps keep AI-generated content consistent with a team's tone$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3c515695-9a2f-4479-901f-6ca785a0e07c', $q$Workflow automation goes beyond one-off copywriting into multi-step GTM task automation$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3c515695-9a2f-4479-901f-6ca785a0e07c', $q$Now backed by Fullcast's broader RevOps suite, offering deeper integration potential with sales execution tools$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3c515695-9a2f-4479-901f-6ca785a0e07c', $q$Faces increasing competition from general-purpose AI assistants like ChatGPT and Claude for basic copywriting tasks$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3c515695-9a2f-4479-901f-6ca785a0e07c', $q$Post-acquisition roadmap is now shaped by Fullcast's RevOps strategy rather than operating as a fully independent product$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3c515695-9a2f-4479-901f-6ca785a0e07c', $q$Team and Enterprise pricing represents a steep jump from the Starter tier for growing teams$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3c515695-9a2f-4479-901f-6ca785a0e07c', $q$Employee and company-size figures have fluctuated significantly, reflecting organizational change around the acquisition$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3c515695-9a2f-4479-901f-6ca785a0e07c', $q$Is Copy.ai free?$q$, $q$Yes, Copy.ai offers a free plan with 2,000 words of chat generation per month, one Brand Voice, and 200 workflow automation credits, with no credit card required.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3c515695-9a2f-4479-901f-6ca785a0e07c', $q$Who owns Copy.ai now?$q$, $q$Copy.ai was acquired by Fullcast, a revenue operations (RevOps) platform company, in October 2025, and is being integrated into Fullcast's Propel product line.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3c515695-9a2f-4479-901f-6ca785a0e07c', $q$Who founded Copy.ai?$q$, $q$Copy.ai was founded in 2020 by Paul Yacoubian and Chris Lu, who previously worked together at the ESO Fund.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3c515695-9a2f-4479-901f-6ca785a0e07c', $q$How much does Copy.ai cost?$q$, $q$Paid plans start at $49/month (Starter, or ~$36/month billed annually) for a single seat, with a Team plan around $249/month and custom Enterprise pricing for larger organizations.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3c515695-9a2f-4479-901f-6ca785a0e07c', $q$What can Copy.ai's workflows automate?$q$, $q$Copy.ai workflows can automate multi-step GTM tasks such as personalized outbound sequences, proposal generation, and content repurposing by chaining AI generation steps with data inputs.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3c515695-9a2f-4479-901f-6ca785a0e07c', $q$Does Copy.ai offer an API?$q$, $q$Yes, API access and bulk workflow execution are available on the higher-tier Team and Enterprise plans.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('3c515695-9a2f-4479-901f-6ca785a0e07c', $q$AI-assisted marketing copywriting$q$, $q$Marketers and content creators use Copy.ai's chat interface and Brand Voice training to draft on-brand marketing copy quickly.$q$, $q$Marketing teams and content creators$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('3c515695-9a2f-4479-901f-6ca785a0e07c', $q$Automated sales outreach workflows$q$, $q$Sales and RevOps teams build multi-step workflows to generate personalized outbound sequences and proposals at scale.$q$, $q$Sales development and RevOps teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('3c515695-9a2f-4479-901f-6ca785a0e07c', $q$GTM content automation at scale$q$, $q$Enterprise GTM organizations integrate Copy.ai's API into existing sales stacks to automate content generation across large customer or prospect volumes.$q$, $q$Enterprise sales and marketing operations$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('3c515695-9a2f-4479-901f-6ca785a0e07c', $q$Free$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["2,000 words/month in chat","1 Brand Voice","200 workflow automation credits","No credit card required"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('3c515695-9a2f-4479-901f-6ca785a0e07c', $q$Starter$q$, $q$$49/month ($36/month billed annually)$q$, $q$Monthly or annual$q$, NULL, $q$["1 seat","Unlimited chat words","Unlimited chat projects","Access to all supported LLMs"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('3c515695-9a2f-4479-901f-6ca785a0e07c', $q$Team$q$, $q$~$249/month (~$2,232/year)$q$, $q$Monthly or annual$q$, NULL, $q$["Unlimited word generation","Priority support","Multi-seat collaboration","Shared workflow templates"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('3c515695-9a2f-4479-901f-6ca785a0e07c', $q$Enterprise$q$, $q$Custom$q$, $q$Custom$q$, NULL, $q$["Guided jumpstart implementation","API access and bulk workflow runs","20+ tech integrations","Dedicated account and support team"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3c515695-9a2f-4479-901f-6ca785a0e07c', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Copy.ai is an AI-powered content generation and go-to-market workflow automation platform, founded in 2020 by Paul Yacoubian and Chris Lu and headquartered in Memphis, Tennessee. It began as an AI copywriting tool and expanded into broader sales and marketing workflow automation.$q$, $q$In October 2025, Copy.ai was acquired by Fullcast, a revenue operations (RevOps) platform company, and is being integrated into Fullcast's Propel product line as its AI execution layer alongside Fullcast's other acquisitions, Ebsta, Atrium, and Commissionly.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3c515695-9a2f-4479-901f-6ca785a0e07c', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$The platform is built around a chat-based AI writing interface, Brand Voice training to keep generated content on-tone, and workflow automation that chains AI generation steps together to automate multi-step tasks like personalized outbound sequences and proposal generation.$q$, $q$Higher-tier plans add API access, bulk workflow execution, and access to a wider set of supported large language models.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3c515695-9a2f-4479-901f-6ca785a0e07c', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Copy.ai offers a free plan with 2,000 words/month of chat generation, one Brand Voice, and 200 workflow credits. The Starter plan is $49/month ($36/month billed annually) for unlimited chat generation and access to all supported LLMs.$q$, $q$The Team plan costs around $249/month for multi-seat collaboration and priority support, while Enterprise offers custom pricing with guided implementation, API access, and a dedicated account team.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('3c515695-9a2f-4479-901f-6ca785a0e07c', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('3c515695-9a2f-4479-901f-6ca785a0e07c', 'd5f794d8-1509-49c9-ac15-6834dce260e9') ON CONFLICT DO NOTHING;
