INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('3c515695-9a2f-4479-901f-6ca785a0e07c', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
