INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('3c515695-9a2f-4479-901f-6ca785a0e07c', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('67b35559-aa14-4347-b26e-f153e6e02e8c', $q$AI-assisted comment moderation$q$, $q$Helps human moderators triage and prioritize potentially problematic comments rather than manually reviewing every submission.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('67b35559-aa14-4347-b26e-f153e6e02e8c', $q$Best-comment highlighting$q$, $q$Surfaces high-quality, constructive comments to reward good-faith engagement and set community tone.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('67b35559-aa14-4347-b26e-f153e6e02e8c', $q$Configurable comment stream settings$q$, $q$Publishers can require pre-moderation, limit posting frequency, or close comments after a set period.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('67b35559-aa14-4347-b26e-f153e6e02e8c', $q$CMS and SSO integration$q$, $q$Integrates with newsroom content management systems and supports single sign-on for reader accounts.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('67b35559-aa14-4347-b26e-f153e6e02e8c', $q$Open-source self-hosting$q$, $q$Core commenting software can be downloaded and self-hosted at no licensing cost.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('67b35559-aa14-4347-b26e-f153e6e02e8c', $q$Managed hosting option$q$, $q$Vox Media offers fully hosted, supported Coral deployments for publishers who don't want to self-host.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('67b35559-aa14-4347-b26e-f153e6e02e8c', $q$Global, multi-language deployment$q$, $q$Used by publishers in roughly 30 countries and 20+ languages.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('67b35559-aa14-4347-b26e-f153e6e02e8c', $q$Moderator training and strategy consulting$q$, $q$Vox Media offers strategic partnership services including engagement strategy and moderation team training.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('67b35559-aa14-4347-b26e-f153e6e02e8c', $q$Core software is free and open source, allowing any publisher to self-host at no licensing cost$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('67b35559-aa14-4347-b26e-f153e6e02e8c', $q$Purpose-built moderation tooling designed specifically for newsroom comment sections$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('67b35559-aa14-4347-b26e-f153e6e02e8c', $q$Proven adoption at major outlets including The Wall Street Journal and The Washington Post$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('67b35559-aa14-4347-b26e-f153e6e02e8c', $q$Mission-driven origin focused on healthy discourse rather than ad-impression maximization$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('67b35559-aa14-4347-b26e-f153e6e02e8c', $q$No public, fixed pricing for the managed/hosted tier — requires a sales conversation for a quote$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('67b35559-aa14-4347-b26e-f153e6e02e8c', $q$Self-hosting requires technical resources to deploy, maintain, and moderate infrastructure$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('67b35559-aa14-4347-b26e-f153e6e02e8c', $q$Smaller ecosystem and market presence than large generic commenting platforms like Disqus$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('67b35559-aa14-4347-b26e-f153e6e02e8c', $q$Primarily optimized for newsroom/publisher use cases rather than general-purpose community forums$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('67b35559-aa14-4347-b26e-f153e6e02e8c', $q$Is Coral free to use?$q$, $q$Yes, Coral's core commenting software is open source and free to self-host. Managed hosting, support, and integration services from Vox Media are priced on a custom, quote basis.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('67b35559-aa14-4347-b26e-f153e6e02e8c', $q$Who created Coral (The Coral Project)?$q$, $q$Coral was launched in 2014 as a collaboration between the Mozilla Foundation, The New York Times, and The Washington Post, funded by the Knight Foundation, and was acquired by Vox Media in 2019.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('67b35559-aa14-4347-b26e-f153e6e02e8c', $q$Which publishers use Coral?$q$, $q$Coral is used by publishers including The Wall Street Journal, The Washington Post, and The Globe and Mail, among others across roughly 30 countries.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('67b35559-aa14-4347-b26e-f153e6e02e8c', $q$Is this the same as Coral Protocol or other 'Coral' products?$q$, $q$No, this Coral is the open-source newsroom commenting platform originally called The Coral Project, unrelated to other unrelated software products that also use the name Coral.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('67b35559-aa14-4347-b26e-f153e6e02e8c', $q$Does Coral use AI for moderation?$q$, $q$Yes, Coral uses AI-assisted tooling to help human moderators triage and prioritize comments that may need review.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('67b35559-aa14-4347-b26e-f153e6e02e8c', $q$Can I self-host Coral?$q$, $q$Yes, Coral's open-source code is available on GitHub and can be self-installed and run on a publisher's own infrastructure at no software cost.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('67b35559-aa14-4347-b26e-f153e6e02e8c', $q$Newsroom comment section moderation$q$, $q$Publishers deploy Coral to run reader comments on articles with editorial-grade moderation tools rather than unmoderated third-party widgets.$q$, $q$News publishers and digital media outlets$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('67b35559-aa14-4347-b26e-f153e6e02e8c', $q$Self-hosted community platform for small newsrooms$q$, $q$Small or nonprofit newsrooms with limited budgets self-host Coral's open-source software to run comments without ongoing licensing fees.$q$, $q$Local and nonprofit newsrooms$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('67b35559-aa14-4347-b26e-f153e6e02e8c', $q$Managed commenting with strategic support$q$, $q$Larger publishers use Vox Media's hosted Coral offering along with consulting and moderator training to scale community engagement strategically.$q$, $q$Large digital publishers and media groups$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('67b35559-aa14-4347-b26e-f153e6e02e8c', $q$Open Source (Self-Hosted)$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Full open-source commenting software","Self-hosted deployment","Core moderation tools","Community support via GitHub"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('67b35559-aa14-4347-b26e-f153e6e02e8c', $q$Managed / Hosted$q$, $q$Custom$q$, $q$Custom$q$, NULL, $q$["Fully hosted SaaS deployment","CMS and SSO integration","Implementation and migration support","Strategic partnership and moderator training"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('67b35559-aa14-4347-b26e-f153e6e02e8c', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Coral (formerly The Coral Project) is an open-source commenting and community platform built specifically for newsrooms. It was launched in 2014 as a collaboration between Mozilla, The New York Times, and The Washington Post, funded by the Knight Foundation, and was acquired by Vox Media in 2019, which now develops and operates it as 'Coral by Vox Media.'$q$, $q$The flagship product, originally called 'Talk,' is designed to make comment sections more constructive and manageable for journalists, in contrast to unmoderated or ad-driven generic commenting widgets.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('67b35559-aa14-4347-b26e-f153e6e02e8c', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Coral provides AI-assisted moderation tooling to help human moderators triage comments, highlights high-quality comments to reward constructive engagement, and offers configurable comment stream settings such as pre-moderation and comment-frequency limits.$q$, $q$It integrates with newsroom CMS platforms and supports single sign-on, and is used by publishers including The Wall Street Journal, The Washington Post, and The Globe and Mail across roughly 30 countries and 20+ languages.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('67b35559-aa14-4347-b26e-f153e6e02e8c', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Coral's core commenting software is open source and free to self-host for any publisher willing to run and maintain it themselves.$q$, $q$Publishers who want managed hosting, CMS/SSO integration, implementation support, or strategic consulting pay Vox Media custom, quote-based pricing scoped to their traffic and support needs — there is no fixed published price list.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('67b35559-aa14-4347-b26e-f153e6e02e8c', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('67b35559-aa14-4347-b26e-f153e6e02e8c', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
