INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('67b35559-aa14-4347-b26e-f153e6e02e8c', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('67b35559-aa14-4347-b26e-f153e6e02e8c', 'd5f794d8-1509-49c9-ac15-6834dce260e9') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('87d8b957-ca86-43e1-bf19-a249b1bd836a', $q$TCO Optimizer$q$, $q$Routes incoming data to different pricing/storage tiers based on business value, letting teams control observability costs without losing query access.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('87d8b957-ca86-43e1-bf19-a249b1bd836a', $q$Unified logs, metrics, and traces$q$, $q$Combines log analytics, metrics monitoring, and distributed tracing in a single full-stack observability platform.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('87d8b957-ca86-43e1-bf19-a249b1bd836a', $q$Unit-based usage pricing$q$, $q$Prices data by 'units' (~$1.50 each) that flex based on data type and processing tier rather than a flat per-GB rate.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('87d8b957-ca86-43e1-bf19-a249b1bd836a', $q$Pay-As-You-Go overage protection$q$, $q$Automatically allows ingestion up to 2x the daily committed quota during traffic spikes rather than dropping data at the limit.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('87d8b957-ca86-43e1-bf19-a249b1bd836a', $q$Multi-region data processing$q$, $q$Processes petabytes of production data daily across eight global regions for data residency and performance.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('87d8b957-ca86-43e1-bf19-a249b1bd836a', $q$Alerting and dashboards$q$, $q$Provides real-time alerting and customizable dashboards across log, metric, and trace data.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('87d8b957-ca86-43e1-bf19-a249b1bd836a', $q$Enterprise integrations$q$, $q$Available on AWS Marketplace and integrates with common cloud and infrastructure monitoring stacks.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('87d8b957-ca86-43e1-bf19-a249b1bd836a', $q$AI-era infrastructure monitoring$q$, $q$Positioned to handle the higher observability data volumes generated by AI-driven infrastructure and workloads.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('87d8b957-ca86-43e1-bf19-a249b1bd836a', $q$TCO Optimizer gives granular, policy-based control over observability spend rather than a flat per-GB bill$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('87d8b957-ca86-43e1-bf19-a249b1bd836a', $q$Unified platform covers logs, metrics, and traces without needing separate point tools$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('87d8b957-ca86-43e1-bf19-a249b1bd836a', $q$Backed by significant, well-known enterprise customers (IBM, Tradeweb, JFrog) and $550M+ in funding$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('87d8b957-ca86-43e1-bf19-a249b1bd836a', $q$No per-seat or per-host fees; all features included on every paid plan$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('87d8b957-ca86-43e1-bf19-a249b1bd836a', $q$No permanent free tier, only a 14-day trial with a limited unit quota$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('87d8b957-ca86-43e1-bf19-a249b1bd836a', $q$Unit-based pricing model can feel complex to evaluate for smaller teams with lower data volumes$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('87d8b957-ca86-43e1-bf19-a249b1bd836a', $q$Better suited to mid-market and enterprise customers than very small teams or hobbyist projects$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('87d8b957-ca86-43e1-bf19-a249b1bd836a', $q$Requires understanding of the tiered pipeline model (Frequent Search, Monitoring, Compliance) to optimize costs effectively$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('87d8b957-ca86-43e1-bf19-a249b1bd836a', $q$How does Coralogix pricing work?$q$, $q$Coralogix uses a unit-based pricing model where one unit costs roughly $1.50 and represents a variable amount of data depending on data type and which processing tier (Frequent Search, Monitoring, Compliance) it's routed to.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('87d8b957-ca86-43e1-bf19-a249b1bd836a', $q$Does Coralogix have a free plan?$q$, $q$No permanent free plan is available, but Coralogix offers a 14-day free trial with no credit card required and full feature access up to a daily quota of 8 units.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('87d8b957-ca86-43e1-bf19-a249b1bd836a', $q$What is the TCO Optimizer?$q$, $q$The TCO Optimizer is Coralogix's cost-control feature that lets teams route data to different pricing/storage tiers based on its business value, so low-priority data costs less to store while high-priority data remains fully searchable.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('87d8b957-ca86-43e1-bf19-a249b1bd836a', $q$Who founded Coralogix?$q$, $q$Coralogix was founded in 2014 by CEO Ariel Assaraf and CTO Yoni Farin and is headquartered in Ramat Gan, in the greater Tel Aviv area of Israel.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('87d8b957-ca86-43e1-bf19-a249b1bd836a', $q$What data types does Coralogix support?$q$, $q$Coralogix supports logs, metrics, and distributed traces in a single unified observability platform.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('87d8b957-ca86-43e1-bf19-a249b1bd836a', $q$Who are Coralogix's main competitors?$q$, $q$Coralogix is commonly compared to Datadog, Splunk, Sumo Logic, New Relic, and Grafana Cloud in the observability market.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('87d8b957-ca86-43e1-bf19-a249b1bd836a', $q$Cost-optimized observability at scale$q$, $q$Engineering teams with rapidly growing log and metric volumes use Coralogix's TCO Optimizer to control observability spend without losing visibility.$q$, $q$DevOps and SRE teams at growth-stage companies$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('87d8b957-ca86-43e1-bf19-a249b1bd836a', $q$Unified monitoring for microservices$q$, $q$Teams running distributed, microservices-based architectures use Coralogix to unify logs, metrics, and traces in one platform for faster incident response.$q$, $q$Platform engineering teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('87d8b957-ca86-43e1-bf19-a249b1bd836a', $q$AI infrastructure monitoring$q$, $q$Organizations running AI/ML infrastructure adopt Coralogix to manage the significantly higher observability data volumes generated by AI workloads.$q$, $q$AI/ML infrastructure and platform teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('87d8b957-ca86-43e1-bf19-a249b1bd836a', $q$Free Trial$q$, $q$Free for 14 days$q$, $q$One-time trial$q$, NULL, $q$["No credit card required","Full feature access","8 units/day quota"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('87d8b957-ca86-43e1-bf19-a249b1bd836a', $q$Pay-As-You-Go$q$, $q$~$1.50/unit$q$, $q$Usage-based$q$, NULL, $q$["Unit-based pricing across logs, metrics, and traces","TCO Optimizer for cost routing","Overage protection up to 2x daily quota","No per-seat or per-host fees"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('87d8b957-ca86-43e1-bf19-a249b1bd836a', $q$Enterprise$q$, $q$Custom$q$, $q$Custom/annual commitment$q$, NULL, $q$["Volume-based custom commitments","Dedicated support","Multi-region deployment","Advanced compliance options"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('87d8b957-ca86-43e1-bf19-a249b1bd836a', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Coralogix is a full-stack observability platform for logs, metrics, and distributed traces, founded in 2014 by Ariel Assaraf (CEO) and Yoni Farin (CTO) and headquartered in Ramat Gan, in the greater Tel Aviv area of Israel, with additional offices across the US, Europe, and India.$q$, $q$The company has raised roughly $550 million in total funding, including a $200 million Series F in June 2026 co-led by Advent International, CPPIB, and Greenfield Partners, and reports more than 5,000 customers worldwide, including IBM, Tradeweb, and JFrog.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('87d8b957-ca86-43e1-bf19-a249b1bd836a', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Coralogix's signature capability is the TCO Optimizer, which routes incoming observability data to different pricing and storage tiers (Frequent Search, Monitoring, Compliance/Archive, or block) based on its business value, avoiding the all-or-nothing indexing cost of legacy observability tools.$q$, $q$The platform processes petabytes of data daily across eight global regions and covers logs, metrics, and traces in a single unified system rather than requiring separate tools for each data type.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('87d8b957-ca86-43e1-bf19-a249b1bd836a', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Coralogix uses unit-based pricing at roughly $1.50 per unit, where the amount of data represented by a unit varies depending on which processing tier the data is routed to.$q$, $q$There is no permanent free plan, but a 14-day free trial with no credit card required offers full feature access and a daily quota of 8 units; a Pay-As-You-Go overage option lets ingestion continue up to double the daily committed quota during usage spikes.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('87d8b957-ca86-43e1-bf19-a249b1bd836a', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('87d8b957-ca86-43e1-bf19-a249b1bd836a', '610c2598-d057-4727-bf3b-e907b0daed7f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('87d8b957-ca86-43e1-bf19-a249b1bd836a', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
